import stripe  # pip install stripe
STRIPE_SECRET = os.environ.get("STRIPE_WEBHOOK_SECRET", "")

@app.post("/webhooks/stripe")
async def stripe_webhook(request: Request) -> dict:
    body = await request.body()
    sig = request.headers.get("Stripe-Signature", "")
    try:
        event = stripe.Webhook.construct_event(body, sig, STRIPE_SECRET)
    except stripe.error.SignatureVerificationError:
        raise HTTPException(status_code=401, detail="Invalid Stripe signature")
    # enqueue event["type"] and event["data"]
    return {"ok": True}

# --- Generic HMAC pattern ---
def verify_hmac(body: bytes, header_sig: str, secret: bytes, prefix: str = "sha256=") -> bool:
    expected = prefix + hmac.new(secret, body, hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected, header_sig)

from dataclasses import dataclass
from typing import Callable

@dataclass
class WebhookHandler:
    source: str
    event_type: str
    description: str
    handler: Callable[[dict], None]

WEBHOOK_CATALOG: list[WebhookHandler] = []

def webhook_event(source: str, event_type: str, description: str):
    """Decorator to register a webhook handler.""""
    def decorator(fn: Callable) -> Callable:
        WEBHOOK_CATALOG.append(WebhookHandler(
            source=source, event_type=event_type,
            description=description, handler=fn
        ))
        return fn
    return decorator

