def dispatch(source: str, event_type: str, payload: dict) -> None:
    key = f"{source}:{event_type}"
    for entry in WEBHOOK_CATALOG:
        if f"{entry.source}:{entry.event_type}" == key:
            entry.handler(payload)
            return
    print(f"No handler registered for {key}")

def list_handlers():
